<?php// Daily_Generation_Report_Individual_Excel_iframe.php// Compact responsive daily generation (till-date) with export buttons (CSV and PDF)// Preserves original calculation logic - adjusted to show days 1..today onlyerror_reporting(0);include "Includes.php"; // keep your original include (DB, helper functions, $Cook_Variable, etc.)// helpers: if getAllDatesBetweenTwoDates isn't defined in your Includes, define itif (!function_exists("getAllDatesBetweenTwoDates")) {    function getAllDatesBetweenTwoDates($startDate, $endDate)    {        $start = DateTime::createFromFormat("d-m-Y", $startDate);        $end = DateTime::createFromFormat("d-m-Y", $endDate);        $dates = [];        if (!$start || !$end) {            return $dates;        }        for ($dt = clone $start; $dt <= $end; $dt->modify("+1 day")) {            $dates[] = $dt->format("d-m-Y");        }        return $dates;    }}// Safe request inputs$Cook_Variable = explode("|", $_COOKIE[$Cook_Name] ?? "");$IMEI = isset($_REQUEST["c1"]) ? base64_decode($_REQUEST["c1"]) : "";$DGR_IMEI = $IMEI; // used in queries in original logic$Format_Type = "";$Device_Name = "";$Site_Location = "";$Closing_Time = "00:00:00";// Fetch device info (preserve original style)$Device_Query =    "SELECT Device_Name,Format_Type,Closing_Time,HTSC_No,Connect_Feeder,Site_Location,State,IMEI FROM device_register WHERE IMEI = '" .    $db->real_escape_string($IMEI) .    "'";if (!($Device_Query_Result = $db->query($Device_Query))) {    die($db->error);}if ($Device_Query_Result->num_rows >= 1) {    $Fetch_Result = $Device_Query_Result->fetch_assoc();    $Device_Name = $Fetch_Result["Device_Name"];    $Site_Location = $Fetch_Result["Site_Location"];    $Format_Type = $Fetch_Result["Format_Type"];    $Closing_Time = $Fetch_Result["Closing_Time"];    $HTSC_No = $Fetch_Result["HTSC_No"];}// Date range: from start of THIS month up to today's date (till-date)$DGR_Start_Date = date("01-m-Y");$DGR_End_Date = date("d-m-Y"); // till-date (today) - requested change$Date_Array = getAllDatesBetweenTwoDates($DGR_Start_Date, $DGR_End_Date);// Pre-allocate arrays used in original logic$Array_Gen = $Array_Import = $Array_Run = $Array_GD = $Array_Lull = $Array_BD = [];$Total_Gen = $Import_LCS = $Run_Hours = $GD_Hours = $BD_Hours = $Lull_Hours = [];$GA_Percent = $MA_Percent = [];// For many queries (the original code used $Cook_Variable[7] etc). Keep them as-is.$DbPrefix = $Cook_Variable[7] ?? ""; // used in pocket_time_calc queries in original code// Iterate dates and compute per-day values (inserting your original logic)foreach ($Date_Array as $DATE_Val) {    // compute date stamps depending on closing time logic (copied from original)    if ($Closing_Time == "00:00:00" || $Closing_Time == "0") {        $Date_St = date("Y-m-d", strtotime($DATE_Val));        $Date_Stamp = date("Y-m-d", strtotime($DATE_Val));        $Yester_Stamp = $Date_Stamp;        $Yester_dmy = $DATE_Val;    } elseif ($Closing_Time >= "10:00:00" || $Closing_Time == "10") {        $Date_St = date("Y-m-d", strtotime($DATE_Val) - 86400);        $Date_Stamp = date("Y-m-d", strtotime($DATE_Val));        $Yester_Stamp = date("Y-m-d", strtotime($DATE_Val));    } else {        $Date_Stamp = date("Y-m-d", strtotime($DATE_Val));        $Date_St = date("Y-m-d", strtotime($DATE_Val));        $Yester_Stamp = date("Y-m-d", strtotime($DATE_Val) + 86400);        $Yester_dmy = date("d.m.Y", strtotime($DATE_Val) + 86400);    }    // default values    $Total_Gen[$DATE_Val] = 0;    $Import_LCS[$DATE_Val] = 0;    $Run_Hours[$DATE_Val] = 0;    $GD_Hours[$DATE_Val] = 0;    $BD_Hours[$DATE_Val] = 0;    $Lull_Hours[$DATE_Val] = 0;    $GA_Percent[$DATE_Val] = 0;    $MA_Percent[$DATE_Val] = 0;    // Branch by Format_Type - preserve original SQLs & calculations    // NOTE: these queries and field names mirror your original code.    if ($Format_Type == 1 || $Format_Type == 6) {        $Gen_Mysql_Query =            "            SELECT IMEI, Date_S, Gen1_Min, Gen1_Max, Run_Min, Run_Max, Gen1H_Min, Gen1H_Max, Line_Min, Line_Max,                    ABS(Import_Min) as Import_Min, ABS(Import_Max) as Import_Max            FROM daily_data            WHERE IMEI = '" .            $db->real_escape_string($DGR_IMEI) .            "' AND Date_S = '" .            $db->real_escape_string($Date_Stamp) .            "'        ";        if ($Gen_Mysql_Query_Result = $db->query($Gen_Mysql_Query)) {            if ($Gen_Mysql_Query_Result->num_rows >= 1) {                $F = $Gen_Mysql_Query_Result->fetch_assoc();                $Import_LCS[$DATE_Val] = $F["Import_Max"] - $F["Import_Min"];                $Total_Gen[$DATE_Val] = $F["Gen1_Max"] - $F["Gen1_Min"];                $Run = $F["Run_Max"] - $F["Run_Min"];                $Gen1H = $F["Gen1H_Max"] - $F["Gen1H_Min"];                // corrections and sanitizations as in original                $Run = $Run > 24 && $Run < 500 ? 24 : $Run;                $Gen1H = $Gen1H > 24 && $Gen1H < 50 ? 24 : $Gen1H;                $Lull_Hours[$DATE_Val] = $Run - $Gen1H;                $Run_Hours[$DATE_Val] = $Gen1H;                $GD_Hours[$DATE_Val] = 24 - ($F["Line_Max"] - $F["Line_Min"]);                $BD_Hours[$DATE_Val] =                    24 -                    ($GD_Hours[$DATE_Val] +                        $Lull_Hours[$DATE_Val] +                        $Run_Hours[$DATE_Val]);                $GA_Percent[$DATE_Val] =                    ((24 - $GD_Hours[$DATE_Val]) / 24) * 100;                $MA_Percent[$DATE_Val] =                    ((24 - $BD_Hours[$DATE_Val]) / 24) * 100;                // filter unrealistics                if (                    $Total_Gen[$DATE_Val] < 0 ||                    $Total_Gen[$DATE_Val] > 15000                ) {                    $Total_Gen[$DATE_Val] = 0;                }                if (                    $Import_LCS[$DATE_Val] < 0 ||                    $Import_LCS[$DATE_Val] > 500                ) {                    $Import_LCS[$DATE_Val] = 0;                }            }        }    } elseif ($Format_Type == 2 || $Format_Type == 4) {        $Gen_Mysql_Query =            "            SELECT IMEI, Date_S, Gen1_Min, Gen1_Max, Gen2_Min, Gen2_Max, Gen1H_Min, Gen1H_Max, Gen2H_Min, Gen2H_Max,                    ABS(Import_Min) as Import_Min, ABS(Import_Max) as Import_Max            FROM daily_data            WHERE IMEI = '" .            $db->real_escape_string($DGR_IMEI) .            "' AND Date_S = '" .            $db->real_escape_string($Date_Stamp) .            "'        ";        if ($Gen_Mysql_Query_Result = $db->query($Gen_Mysql_Query)) {            if ($Gen_Mysql_Query_Result->num_rows >= 1) {                $F = $Gen_Mysql_Query_Result->fetch_assoc();                $Import_LCS[$DATE_Val] = $F["Import_Max"] - $F["Import_Min"];                $Total_Gen1 = $F["Gen1_Max"] - $F["Gen1_Min"];                $Gen2 = $F["Gen2_Max"] - $F["Gen2_Min"];                $Run_Hours[$DATE_Val] =                    $F["Gen1H_Max"] -                    $F["Gen1H_Min"] +                    ($F["Gen2H_Max"] - $F["Gen2H_Min"]);                $Total_Gen[$DATE_Val] = $Total_Gen1 + $Gen2;                // sanitize                $Run_Hours[$DATE_Val] =                    $Run_Hours[$DATE_Val] > 24 && $Run_Hours[$DATE_Val] < 500                        ? 24                        : $Run_Hours[$DATE_Val];                if (                    $Total_Gen[$DATE_Val] < 0 ||                    $Total_Gen[$DATE_Val] > 10000                ) {                    $Total_Gen[$DATE_Val] = 0;                }                if (                    $Import_LCS[$DATE_Val] < 0 ||                    $Import_LCS[$DATE_Val] > 500                ) {                    $Import_LCS[$DATE_Val] = 0;                }                // pocket_time_calc derived BD/GD if available in your system (preserve original approach)                $POC_Mysql_Query =                    "                    SELECT IMEI, Date_S, Error_Type, SUM(Time_Diff) as Diff                    FROM " .                    $db->real_escape_string($DbPrefix) .                    ".pocket_time_calc                    WHERE IMEI = " .                    intval($DGR_IMEI) .                    " AND (Date_S = '" .                    $db->real_escape_string($Date_St) .                    "' OR Date_S = '" .                    $db->real_escape_string($Yester_Stamp) .                    "')                      AND (CASE WHEN (Date_S = '" .                    $db->real_escape_string($Date_St) .                    "') THEN HOUR(CAST(Time_S AS TIME)) >= '" .                    intval($Closing_Time) .                    "' ELSE HOUR(CAST(Time_S AS TIME)) < '" .                    intval($Closing_Time) .                    "' END)                    GROUP BY Error_Type                ";                if ($POC_Mysql_Query_Result = $db->query($POC_Mysql_Query)) {                    while (                        $POC_Fetch_Result = $POC_Mysql_Query_Result->fetch_assoc()                    ) {                        $et = $POC_Fetch_Result["Error_Type"];                        $diffSec = $POC_Fetch_Result["Diff"];                        if ($et == "BD Hours") {                            $BD_Hours[$DATE_Val] = round($diffSec / 3600, 1);                            if (                                !(                                    $BD_Hours[$DATE_Val] >= 0 &&                                    $BD_Hours[$DATE_Val] <= 24                                )                            ) {                                $BD_Hours[$DATE_Val] = 0;                            }                        } elseif ($et == "GD Hours") {                            $GD_Hours[$DATE_Val] = round($diffSec / 3600, 1);                            if (                                !(                                    $GD_Hours[$DATE_Val] >= 0 &&                                    $GD_Hours[$DATE_Val] <= 25                                )                            ) {                                $GD_Hours[$DATE_Val] = 0;                            }                        }                    }                }                $Array_GD[$DATE_Val] = $GD_Hours[$DATE_Val] ?? 0;                $Array_BD[$DATE_Val] = $BD_Hours[$DATE_Val] ?? 0;                $Lull_Hours[$DATE_Val] =                    24 -                    (($Run_Hours[$DATE_Val] ?? 0) +                        ($BD_Hours[$DATE_Val] ?? 0) +                        ($GD_Hours[$DATE_Val] ?? 0));                if ($Lull_Hours[$DATE_Val] < 0) {                    $Lull_Hours[$DATE_Val] = 0;                }                $GA_Percent[$DATE_Val] =                    ((24 - ($GD_Hours[$DATE_Val] ?? 0)) / 24) * 100;                $MA_Percent[$DATE_Val] =                    ((24 - ($BD_Hours[$DATE_Val] ?? 0)) / 24) * 100;            }        }    } elseif (in_array($Format_Type, [3, 8, 10])) {        // other formats mostly similar to original code handling — use daily_data selects        $Gen_Mysql_Query =            "            SELECT IMEI, Date_S, Gen1_Min, Gen1_Max, Gen1H_Min, Gen1H_Max, Gen2H_Min, Gen2H_Max,                   ABS(Import_Min) as Import_Min, ABS(Import_Max) as Import_Max, Run_Min, Run_Max, Line_Min, Line_Max            FROM daily_data            WHERE IMEI = '" .            $db->real_escape_string($DGR_IMEI) .            "' AND Date_S = '" .            $db->real_escape_string($Date_Stamp) .            "'        ";        if ($Gen_Mysql_Query_Result = $db->query($Gen_Mysql_Query)) {            if ($Gen_Mysql_Query_Result->num_rows >= 1) {                $F = $Gen_Mysql_Query_Result->fetch_assoc();                // some formats return Gen1_Max as total generation directly (keep original guards)                if (isset($F["Gen1_Max"]) && isset($F["Gen1_Min"])) {                    $Total_Gen[$DATE_Val] = $F["Gen1_Max"] - $F["Gen1_Min"];                }                if (isset($F["Import_Max"]) && isset($F["Import_Min"])) {                    $Import_LCS[$DATE_Val] =                        $F["Import_Max"] - $F["Import_Min"];                }                // Run/GD/BD calculations (use available fields)                if (isset($F["Gen1H_Max"]) && isset($F["Gen1H_Min"])) {                    $Run_Hours[$DATE_Val] = $F["Gen1H_Max"] - $F["Gen1H_Min"];                    $Run_Hours[$DATE_Val] =                        $Run_Hours[$DATE_Val] > 24 &&                        $Run_Hours[$DATE_Val] < 500                            ? 24                            : $Run_Hours[$DATE_Val];                }                if (isset($F["Line_Max"]) && isset($F["Line_Min"])) {                    $GD_Hours[$DATE_Val] =                        24 - ($F["Line_Max"] - $F["Line_Min"]);                }                $BD_Hours[$DATE_Val] =                    24 -                    (($GD_Hours[$DATE_Val] ?? 0) +                        ($Lull_Hours[$DATE_Val] ?? 0) +                        ($Run_Hours[$DATE_Val] ?? 0));                $Lull_Hours[$DATE_Val] =                    24 -                    (($Run_Hours[$DATE_Val] ?? 0) +                        ($BD_Hours[$DATE_Val] ?? 0) +                        ($GD_Hours[$DATE_Val] ?? 0));                if ($Lull_Hours[$DATE_Val] < 0) {                    $Lull_Hours[$DATE_Val] = 0;                }                $GA_Percent[$DATE_Val] =                    ((24 - ($GD_Hours[$DATE_Val] ?? 0)) / 24) * 100;                $MA_Percent[$DATE_Val] =                    ((24 - ($BD_Hours[$DATE_Val] ?? 0)) / 24) * 100;                // sanitise extremes                if (                    $Total_Gen[$DATE_Val] < 0 ||                    $Total_Gen[$DATE_Val] > 20000                ) {                    $Total_Gen[$DATE_Val] = 0;                }                if (                    $Import_LCS[$DATE_Val] < 0 ||                    $Import_LCS[$DATE_Val] > 500                ) {                    $Import_LCS[$DATE_Val] = 0;                }            }        }    } elseif ($Format_Type == 7) {                $date__stamp = date_create($Date_Stamp);        $DateeOn = date_format($date__stamp, "j-n-y");        $Gen_Mysql_Query =            "SELECT     IMEI,    Date,    Windspeed,    (SELECT MIN(Reactive_Total_Gen_Export)      FROM va_swami.device_data_f7      WHERE IMEI = '" .            $DGR_IMEI .            "'        AND Date_S = '" .            $Date_Stamp .            "'                AND Reactive_Total_Gen_Export != '') AS Gen1_Min,    (SELECT (MAX(Reactive_Total_Gen_Export) )      FROM va_swami.device_data_f7      WHERE IMEI = '" .            $DGR_IMEI .            "'        AND Date_S = '" .            $Date_Stamp .            "'               AND Reactive_Total_Gen_Export != '') AS Gen1_Max,    (Select Min(Min3_Active_Power)  from va_swami.device_data_f7  Where IMEI='" .            $DGR_IMEI .            "'  and Date_S='" .            $Date_Stamp .            "'  and Min3_Active_Power>'0'  and Min3_Active_Power!='') as Run_Min,(Select Max(Min3_Active_Power)  from va_swami.device_data_f7  Where IMEI='" .            $DGR_IMEI .            "'  and Date_S='" .            $Date_Stamp .            "'  and Min3_Active_Power>'0'  and Min3_Active_Power!='') as Run_Max,    (SELECT MIN(Min3_Wind_Dir)      FROM va_swami.device_data_f7      WHERE IMEI = '" .            $DGR_IMEI .            "'        AND Date_S = '" .            $Date_Stamp .            "'        AND Date = '" .            $DateeOn .            "'        AND Min3_Wind_Dir != '') AS Gen1H_Min,    (SELECT MAX(Min3_Wind_Dir)      FROM va_swami.device_data_f7      WHERE IMEI = '" .            $DGR_IMEI .            "'        AND Date_S = '" .            $Date_Stamp .            "'        AND Date = '" .            $DateeOn .            "'        AND Min3_Wind_Dir != '') AS Gen1H_Max,    (SELECT MIN(Min3_Wind_Speed)      FROM va_swami.device_data_f7      WHERE IMEI = '" .            $DGR_IMEI .            "'        AND Date_S = '" .            $Date_Stamp .            "'        AND Date = '" .            $DateeOn .            "'        AND Min3_Wind_Speed != '') AS Line_Min,    (SELECT MAX(Min3_Wind_Speed)      FROM va_swami.device_data_f7      WHERE IMEI = '" .            $DGR_IMEI .            "'        AND Date_S = '" .            $Date_Stamp .            "'        AND Date = '" .            $DateeOn .            "'        AND Min3_Wind_Speed != '') AS Line_Max,    (SELECT MIN(Stopped_Hours)      FROM va_swami.device_data_f7      WHERE IMEI = '" .            $DGR_IMEI .            "'        AND Date_S = '" .            $Date_Stamp .            "'        AND Date = '" .            $DateeOn .            "'        AND Stopped_Hours != '') AS Import_Min,    (SELECT MAX(Stopped_Hours)      FROM va_swami.device_data_f7      WHERE IMEI = '" .            $DGR_IMEI .            "'        AND Date_S = '" .            $Date_Stamp .            "'        AND Date = '" .            $DateeOn .            "'        AND Stopped_Hours != '') AS Import_Max,    (SELECT MIN(Grid_failure_Hours)      FROM va_swami.device_data_f7      WHERE IMEI = '" .            $DGR_IMEI .            "'        AND Date_S = '" .            $Date_Stamp .            "'        AND Date = '" .            $DateeOn .            "'        AND Grid_failure_Hours != ''        AND Grid_failure_Hours > '0') AS Total_hrs_Min,    (SELECT MAX(Grid_failure_Hours)      FROM va_swami.device_data_f7      WHERE IMEI = '" .            $DGR_IMEI .            "'        AND Date_S = '" .            $Date_Stamp .            "'        AND Date = '" .            $DateeOn .            "'        AND Grid_failure_Hours != ''        AND Grid_failure_Hours > 0) AS Total_hrs_MaxFROM va_swami.device_data_f7 WHERE IMEI = '" .            $DGR_IMEI .            "'   AND Date_S = '" .            $Date_Stamp .            "' ORDER BY Date_S DESC LIMIT 1";        if ($Gen_Mysql_Query_Result = $db->query($Gen_Mysql_Query)) {            if ($Gen_Mysql_Query_Result->num_rows >= 1) {                $F = $Gen_Mysql_Query_Result->fetch_assoc();                // some formats return Gen1_Max as total generation directly (keep original guards)                if (isset($F["Gen1_Max"]) && isset($F["Gen1_Min"])) {                    $Total_Gen[$DATE_Val] =                        ($F["Gen1_Max"] - $F["Gen1_Min"]) * 1000;                }                if (isset($F["Import_Max"]) && isset($F["Import_Min"])) {                    $Import_LCS[$DATE_Val] =                        $F["Import_Max"] - $F["Import_Min"];                }                // Run/GD/BD calculations (use available fields)                if (isset($F["Run_Max"]) && isset($F["Run_Min"])) {                    $Run_Hours[$DATE_Val] = $F["Run_Max"] - $F["Run_Min"];                    //$Run_Hours[$DATE_Val] = ($Run_Hours[$DATE_Val] > 24 && $Run_Hours[$DATE_Val] < 500) ? 24 : $Run_Hours[$DATE_Val];                    if ($Run_Hours[$DATE_Val] > 24) {                        $Run_Hours[$DATE_Val] = " ";                    }                }                if (isset($F["Line_Max"]) && isset($F["Line_Min"])) {                    $GD_Hours[$DATE_Val] =                        24 - ($F["Line_Max"] - $F["Line_Min"]);                }                $BD_Hours[$DATE_Val] =                    24 -                    (($GD_Hours[$DATE_Val] ?? 0) +                        ($Lull_Hours[$DATE_Val] ?? 0) +                        ($Run_Hours[$DATE_Val] ?? 0));                $Lull_Hours[$DATE_Val] =                    24 -                    (($Run_Hours[$DATE_Val] ?? 0) +                        ($BD_Hours[$DATE_Val] ?? 0) +                        ($GD_Hours[$DATE_Val] ?? 0));                if ($Lull_Hours[$DATE_Val] < 0) {                    $Lull_Hours[$DATE_Val] = 0;                }                $GA_Percent[$DATE_Val] =                    ((24 - ($GD_Hours[$DATE_Val] ?? 0)) / 24) * 100;                $MA_Percent[$DATE_Val] =                    ((24 - ($BD_Hours[$DATE_Val] ?? 0)) / 24) * 100;                // sanitise extremes                if (                    $Total_Gen[$DATE_Val] < 0 ||                    $Total_Gen[$DATE_Val] > 20000                ) {                    $Total_Gen[$DATE_Val] = 0;                }                if (                    $Import_LCS[$DATE_Val] < 0 ||                    $Import_LCS[$DATE_Val] > 500                ) {                    $Import_LCS[$DATE_Val] = 0;                }            }        }    } else {        // default: no records found - keep zeros    }    // Final per-day sanitization (original style)    $Array_Gen[$DATE_Val] = isset($Total_Gen[$DATE_Val])        ? round($Total_Gen[$DATE_Val], 2)        : 0;    $Array_Import[$DATE_Val] = isset($Import_LCS[$DATE_Val])        ? round($Import_LCS[$DATE_Val], 2)        : 0;    $Array_Run[$DATE_Val] = isset($Run_Hours[$DATE_Val])        ? round($Run_Hours[$DATE_Val], 2)        : 0;    $Array_GD[$DATE_Val] = isset($GD_Hours[$DATE_Val])        ? round($GD_Hours[$DATE_Val], 2)        : 0;    $Array_BD[$DATE_Val] = isset($BD_Hours[$DATE_Val])        ? round($BD_Hours[$DATE_Val], 2)        : 0;    $Array_Lull[$DATE_Val] = isset($Lull_Hours[$DATE_Val])        ? round($Lull_Hours[$DATE_Val], 2)        : 0;    $GA_Percent[$DATE_Val] = isset($GA_Percent[$DATE_Val])        ? round($GA_Percent[$DATE_Val], 2)        : 0;    $MA_Percent[$DATE_Val] = isset($MA_Percent[$DATE_Val])        ? round($MA_Percent[$DATE_Val], 2)        : 0;}// Helper to sum arrays safely (mimic your earlier arraySumRecursive)if (!function_exists("arraySumRecursive")) {    function arraySumRecursive($arr)    {        $sum = 0;        if (!is_array($arr)) {            return 0;        }        foreach ($arr as $v) {            if (is_array($v)) {                $sum += arraySumRecursive($v);            } else {                $sum += floatval($v);            }        }        return $sum;    }}?><!doctype html><html lang="en"><head><meta charset="utf-8"><title>Daily Generation Report - <?= htmlspecialchars($Device_Name) ?></title><meta name="viewport" content="width=device-width,initial-scale=1"><link href="https://fonts.googleapis.com/css2?family=Roboto:wght@300;400;600&display=swap" rel="stylesheet"><style>:root{--bg:#f6f8fb;--card:#fff;--muted:#666;--accent:#0f4da2}*{box-sizing:border-box;font-family:Roboto,Arial,Helvetica,sans-serif}body{margin:0;background:var(--bg);color:#111;padding:10px}.container{max-width:1150px;margin:0 auto;background:transparent}.header{display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:8px}.title{font-weight:700;font-size:16px}.controls{display:flex;gap:8px}.btn{background:var(--accent);color:#fff;border:0;padding:8px 10px;border-radius:6px;cursor:pointer;font-weight:600}.btn.secondary{background:#2d2d2d}.compact-table{width:100%;border-collapse:collapse;background:var(--card);border-radius:6px;overflow:hidden;box-shadow:0 4px 14px rgba(20,30,50,0.06)}.compact-table thead th{background:var(--accent);color:#fff;padding:8px 6px;font-size:12px;text-align:center;position:sticky;top:0;z-index:2}.compact-table tbody td{padding:6px 6px;font-size:13px;border-bottom:1px solid #f1f6fb;text-align:center}.compact-table tbody tr:nth-child(even){background:#fbfdff}.kpi-row{display:flex;gap:10px;justify-content:center;margin:12px 0}.kpi{background:var(--card);padding:10px 14px;border-radius:8px;box-shadow:0 6px 18px rgba(16,30,40,0.05);min-width:140px;text-align:center}.kpi .label{font-size:12px;color:var(--muted)}.kpi .val{font-weight:700;font-size:18px;margin-top:6px}.small{font-size:12px;color:var(--muted)}.center-col{ text-align:center }@media(max-width:820px){    .header{flex-direction:column;align-items:flex-start}    .kpi-row{flex-direction:column;align-items:center}    .controls{width:100%;justify-content:flex-start}}</style><!-- Export libraries --><script src="https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js"></script><script src="https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js"></script><script>// Disable right clickdocument.addEventListener('contextmenu', event => event.preventDefault());// Disable common inspect keysdocument.onkeydown = function(e) {    if (e.keyCode == 123) { // F12        return false;    }    if (e.ctrlKey && e.shiftKey && (e.keyCode == 73 || e.keyCode == 67 || e.keyCode == 74)) {        return false;    }    if (e.ctrlKey && e.keyCode == 85) { // Ctrl+U        return false;    }};</script></head><body><div class="container" id="report-root">    <div class="header">        <div>            <div class="title">Daily Generation Detail - <?= htmlspecialchars(                $Device_Name            ) ?></div>            <div class="small">HTSC : <?= htmlspecialchars(                $HTSC_No            ) ?>  |&nbsp; Location: <?= htmlspecialchars(      $Site_Location  ) ?> &nbsp;			</div>        </div>        <div class="controls">            <button class="btn" id="btnExportCSV">Export CSV</button>            <button class="btn secondary" id="btnExportPDF">Export PDF</button>            <button class="btn" id="btnPrint" onclick="window.print()">Print</button>        </div>    </div>        <!-- Compact table -->    <div id="table-wrap">        <table class="compact-table" id="daily-table" role="table" aria-label="Daily Generation Table">            <thead>                <tr>                    <th>Gen Date</th>                    <th>Export (kWh)</th>                    <th>Import (kWh)</th>                    <th>Total Hrs</th>                    <th>Run Hrs</th>                    <th>GD Hrs</th>                    <th>BD Hrs</th>                    <th>Lull Hrs</th>                    <th>GA %</th>                    <th>MA %</th>                </tr>            </thead>            <tbody>                <?php // Show rows: only days up to today (already Date_Array is till-date)                if (count($Date_Array) > 0) {                    foreach ($Date_Array as $DATE_Val) {                        // Show zeroes as '0.00' or original '000' style if you prefer                        $exportVal = isset($Array_Gen[$DATE_Val])                            ? number_format($Array_Gen[$DATE_Val], 0)                            : "0.00";                        $importVal = isset($Array_Import[$DATE_Val])                            ? number_format($Array_Import[$DATE_Val], 0)                            : "0.00";                        $totalHrs = "24";                        $runVal = isset($Array_Run[$DATE_Val])                            ? number_format($Array_Run[$DATE_Val], 0)                            : "0.00";                        $gdVal = isset($Array_GD[$DATE_Val])                            ? number_format($Array_GD[$DATE_Val], 0)                            : "0.00";                        $bdVal = isset($Array_BD[$DATE_Val])                            ? number_format($Array_BD[$DATE_Val], 0)                            : "0.00";                        $lullVal = isset($Array_Lull[$DATE_Val])                            ? number_format($Array_Lull[$DATE_Val], 0)                            : "0.00";                        $gaVal = isset($GA_Percent[$DATE_Val])                            ? number_format($GA_Percent[$DATE_Val], 0)                            : "0.00";                        $maVal = isset($MA_Percent[$DATE_Val])                            ? number_format($MA_Percent[$DATE_Val], 0)                            : "0.00";                        echo "<tr>";                        echo "<td class='center-col'>{$DATE_Val}</td>";                        echo "<td class='center-col'>{$exportVal}</td>";                        echo "<td class='center-col'>{$importVal}</td>";                        echo "<td class='center-col'>{$totalHrs}</td>";                        echo "<td class='center-col'>{$runVal}</td>";                        echo "<td class='center-col'>{$gdVal}</td>";                        echo "<td class='center-col'>{$bdVal}</td>";                        echo "<td class='center-col'>{$lullVal}</td>";                        echo "<td class='center-col'>{$gaVal}</td>";                        echo "<td class='center-col'>{$maVal}</td>";                        echo "</tr>";                    }                } else {                    echo "<tr><td colspan='10' style='padding:12px;text-align:center;color:#666'>Records Not Found</td></tr>";                }// Totals row?>                <tr style="font-weight:700;background:#eef6ff">                    <td class="center-col">Total</td>                    <td class="center-col"><?= number_format(                        arraySumRecursive($Array_Gen),                        2                    ) ?></td>                    <td class="center-col"><?= number_format(                        arraySumRecursive($Array_Import),                        2                    ) ?></td>                    <td class="center-col">--</td>                    <td class="center-col"><?= number_format(                        arraySumRecursive($Array_Run),                        2                    ) ?></td>                    <td class="center-col"><?= number_format(                        arraySumRecursive($Array_GD),                        2                    ) ?></td>                    <td class="center-col"><?= number_format(                        arraySumRecursive($Array_BD),                        2                    ) ?></td>                    <td class="center-col"><?= number_format(                        arraySumRecursive($Array_Lull),                        2                    ) ?></td>                    <td class="center-col">--</td>                    <td class="center-col">--</td>                </tr>            </tbody>        </table>    </div></div><script>// CSV exportfunction downloadCSV(filename, rows) {    var processRow = function (row) {        var finalVal = '';        for (var j = 0; j < row.length; j++) {            var innerValue = row[j] === null ? '' : row[j].toString();            if (row[j] instanceof Date) {                innerValue = row[j].toLocaleString();            }            var result = innerValue.replace(/"/g, '""');            if (result.search(/("|,|\n)/g) >= 0)                result = '"' + result + '"';            if (j > 0)                finalVal += ',';            finalVal += result;        }        return finalVal + '\n';    };    var csvFile = '';    for (var i = 0; i < rows.length; i++) {        csvFile += processRow(rows[i]);    }    var blob = new Blob([csvFile], { type: 'text/csv;charset=utf-8;' });    var link = document.createElement("a");    if (link.download !== undefined) { // feature detection        var url = URL.createObjectURL(blob);        link.setAttribute("href", url);        link.setAttribute("download", filename);        link.style.visibility = 'hidden';        document.body.appendChild(link);        link.click();        document.body.removeChild(link);    }}document.getElementById('btnExportCSV').addEventListener('click', function () {    var table = document.getElementById('daily-table');    var rows = [];    for (var i = 0, row; row = table.rows[i]; i++) {        var rowData = [];        for (var j = 0, col; col = row.cells[j]; j++) {            rowData.push(col.innerText.trim());        }        rows.push(rowData);    }    var filename = 'daily_generation_<?= preg_replace(        "/[^A-Za-z0-9]/",        "_",        $Device_Name    ) ?>_<?= date("Y-m-d") ?>.csv';    downloadCSV(filename, rows);});// PDF export using html2canvas + jsPDFdocument.getElementById('btnExportPDF').addEventListener('click', function () {    const root = document.getElementById('report-root');    // temporarily enlarge for better quality    const scale = 2;    html2canvas(root, { scale: scale, useCORS: true, backgroundColor: '#ffffff' }).then(canvas => {        const imgData = canvas.toDataURL('image/png');        const { jsPDF } = window.jspdf;        const pdf = new jsPDF('p', 'pt', 'a4');        const pageWidth = pdf.internal.pageSize.getWidth();        const pageHeight = pdf.internal.pageSize.getHeight();        const imgWidth = pageWidth - 40; // margins        const imgHeight = (canvas.height * imgWidth) / canvas.width;        let position = 20;        if (imgHeight <= pageHeight - 40) {            pdf.addImage(imgData, 'PNG', 20, position, imgWidth, imgHeight);        } else {            // multi-page            let heightLeft = imgHeight;            let y = 20;            let img = imgData;            while (heightLeft > 0) {                pdf.addImage(img, 'PNG', 20, y, imgWidth, imgHeight);                heightLeft -= (pageHeight - 40);                if (heightLeft > 0) pdf.addPage();                y = 20 - (imgHeight - heightLeft);            }        }        pdf.save('daily_generation_<?= preg_replace(            "/[^A-Za-z0-9]/",            "_",            $Device_Name        ) ?>_<?= date("Y-m-d") ?>.pdf');    }).catch(err => {        alert('Could not export PDF: ' + err.message);    });});</script></body></html>